// ── Per-type op timings ─────────────────────────────────────────────────

template <typename Fn>
static double bench_ns(Fn fn)
{
   using clock = std::chrono::high_resolution_clock;
   for (int i = 0; i < 50; ++i) { fn(); clobber_memory(); }
   std::size_t iters = 0;
   auto start = clock::now();
   while (std::chrono::duration_cast<std::chrono::microseconds>(clock::now() - start).count() < 10'000)
   { fn(); clobber_memory(); ++iters; }
   auto ns = std::chrono::duration_cast<std::chrono::nanoseconds>(clock::now() - start).count();
   return iters > 0 ? static_cast<double>(ns) / iters : 0.0;
}

// Instances are constructed by emitted per-type factories (make_FuzzSnnn).

struct OpTotals
{
   double packsize_frac = 0;
   double packsize_bin  = 0;
   double pack_frac     = 0;
   double pack_bin      = 0;
   double validate_frac = 0;
   double unpack_frac   = 0;
   double unpack_bin    = 0;
   int    type_count    = 0;
};

template <typename T>
void bench_type(OpTotals& totals, const T& v)
{
   auto bin_bytes  = psio::convert_to_bin(v);
   auto frac_bytes = psio::to_frac(v);

   totals.packsize_frac += bench_ns([&] {
      auto s = psio::fracpack_size(v); do_not_optimize(s);
   });
   totals.packsize_bin += bench_ns([&] {
      psio::bin_detail::bin_size_cache c;
      auto s = psio::compute_bin_size(v, c);
      do_not_optimize(s);
   });
   totals.pack_frac += bench_ns([&] {
      auto b = psio::to_frac(v); do_not_optimize(b.data());
   });
   totals.pack_bin += bench_ns([&] {
      auto b = psio::convert_to_bin(v); do_not_optimize(b.data());
   });
   totals.validate_frac += bench_ns([&] {
      auto r = psio::validate_frac<T>({frac_bytes.data(), frac_bytes.size()});
      do_not_optimize(r);
   });
   totals.unpack_frac += bench_ns([&] {
      T u{};
      (void)psio::from_frac(u, std::span<const char>(frac_bytes.data(), frac_bytes.size()));
      do_not_optimize(u);
   });
   totals.unpack_bin += bench_ns([&] {
      T u{};
      psio::input_stream s{bin_bytes.data(), bin_bytes.size()};
      psio::from_bin(u, s);
      do_not_optimize(u);
   });
   ++totals.type_count;
}

